import { Button } from 'antd';
import { ArrowLeftOutlined } from '@ant-design/icons';

export const JournalManiaContainer = ({ onBack }) => {
  return (
      <div>
        <div style={{ display: 'flex', alignItems: 'baseline', gap: '10px' }}>
            <Button shape="circle" onClick={onBack}>
                <ArrowLeftOutlined />
            </Button>
            <h2>Journal Mania</h2>
        </div>
        <p>This is the Journal Mania project page. Here you can find details about the project, its features, and how it was developed.</p>
        <iframe 
            title="Journal Mania Figma Prototype"
            style={{ 
                //border: '1px solid rgba(0, 0, 0, 0.1)', 
                width: '450px', 
                height: '800px' 
            }} 
            src="https://embed.figma.com/proto/hDM9h4AqW79ZhFxiW7rw4C/Journal-Mania?node-id=19-160&scaling=scale-down&content-scaling=fixed&page-id=4%3A2&starting-point-node-id=19%3A160&embed-host=share"
            allowfullscreen
        >
        </iframe>
      </div>
  );
}
